import { Request, Response } from 'express';
import { User, UserProfile } from '../models';
import { ValidationError, NotFoundError } from '../errors';

export async function updateUserSettings(
  req: Request,
  res: Response
): Promise<void> {
  const { userId } = req.params;
  const { preferences } = req.body;

  const user = await User.findById(userId);

  if (!user) {
    throw new NotFoundError('User not found');
  }

  // Check if profile exists, create one if it doesn't
  if (!user.profile) {
    user.profile = {
      preferences: {},
      displayName: '',
      avatar: '',
    };
  }

  user.profile.preferences = {
    ...user.profile.preferences,
    ...preferences,
  };

  await user.save();

  res.json({ success: true, profile: user.profile });
}

export async function getUserProfile(
  req: Request,
  res: Response
): Promise<void> {
  const userId = req.params.userId;
  const user = await User.findById(userId);

  if (!user) {
    throw new NotFoundError('User not found');
  }

  if (!user.profile) {
    res.json({ profile: null });
    return;
  }

  res.json({ profile: user.profile });
}
```

The fix:
1. Added a check for `!user.profile` before accessing `preferences`
2. When profile is missing, initialize it with default values
3. This prevents the 500 error and allows users with empty profiles to successfully update their settings
